import { boolean, integer, jsonb, numeric, pgTable, text, timestamp, uuid, varchar } from "drizzle-orm/pg-core";
export const billingSubscriptionsTable = pgTable("billing_subscriptions", {
    id: uuid("id").primaryKey(),
    userId: uuid("user_id").notNull(),
    planId: uuid("plan_id").notNull(),
    previousPlanId: uuid("previous_plan_id"),
    status: varchar("status", { length: 40 }).notNull(),
    billingCycle: varchar("billing_cycle", { length: 20 }).notNull(),
    renewalMode: varchar("renewal_mode", { length: 20 }).notNull(),
    startDate: timestamp("start_date").notNull(),
    currentPeriodStart: timestamp("current_period_start").notNull(),
    currentPeriodEnd: timestamp("current_period_end").notNull(),
    nextBillingAt: timestamp("next_billing_at"),
    graceEndsAt: timestamp("grace_ends_at"),
    trialEndsAt: timestamp("trial_ends_at"),
    cancelAtPeriodEnd: boolean("cancel_at_period_end").notNull(),
    cancelledAt: timestamp("cancelled_at"),
    autoRenew: boolean("auto_renew").notNull(),
    defaultPaymentMethodId: uuid("default_payment_method_id"),
    lastInvoiceId: uuid("last_invoice_id"),
    gatewayCustomerId: varchar("gateway_customer_id", { length: 150 }),
    gatewaySubscriptionId: varchar("gateway_subscription_id", { length: 150 }),
    purchasedPlanSnapshot: jsonb("purchased_plan_snapshot").notNull(),
    purchasedPriceAmount: numeric("purchased_price_amount").notNull(),
    purchasedCurrencyCode: varchar("purchased_currency_code", { length: 3 }).notNull(),
    purchasedDurationMonths: integer("purchased_duration_months").notNull(),
    metadata: jsonb("metadata").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingPaymentMethodsTable = pgTable("billing_payment_methods", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    userId: uuid("user_id"),
    type: varchar("type", { length: 40 }).notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    stripeCustomerId: varchar("stripe_customer_id", { length: 150 }),
    stripePaymentMethodId: varchar("stripe_payment_method_id", { length: 150 }),
    stripeSetupIntentId: varchar("stripe_setup_intent_id", { length: 150 }),
    displayBrand: varchar("display_brand", { length: 80 }),
    last4: varchar("last4", { length: 4 }),
    isDefault: boolean("is_default").notNull(),
    metadata: jsonb("metadata").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
    deletedAt: timestamp("deleted_at"),
});
export const billingPaymentProfilesTable = pgTable("billing_payment_profiles", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    userId: uuid("user_id"),
    fullName: varchar("full_name", { length: 255 }).notNull(),
    cardNumberEncrypted: text("card_number_encrypted").notNull(),
    expiryMonth: integer("expiry_month").notNull(),
    expiryYear: integer("expiry_year").notNull(),
    cvcEncrypted: text("cvc_encrypted").notNull(),
    addressLine1: varchar("address_line_1", { length: 255 }).notNull(),
    addressLine2: varchar("address_line_2", { length: 255 }),
    city: varchar("city", { length: 100 }).notNull(),
    state: varchar("state", { length: 100 }).notNull(),
    country: varchar("country", { length: 100 }).notNull(),
    postalCode: varchar("postal_code", { length: 20 }).notNull(),
    last4: varchar("last4", { length: 4 }).notNull(),
    displayBrand: varchar("display_brand", { length: 80 }).notNull(),
    isDefault: boolean("is_default").notNull(),
    metadata: jsonb("metadata").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
    deletedAt: timestamp("deleted_at"),
});
export const billingInvoicesTable = pgTable("billing_invoices", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    subscriptionId: uuid("subscription_id").notNull(),
    invoiceNumber: varchar("invoice_number", { length: 80 }).notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    subtotalAmount: numeric("subtotal_amount").notNull(),
    taxAmount: numeric("tax_amount").notNull(),
    discountAmount: numeric("discount_amount").notNull(),
    creditAppliedAmount: numeric("credit_applied_amount").notNull(),
    totalAmount: numeric("total_amount").notNull(),
    paidAmount: numeric("paid_amount").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    dueDate: timestamp("due_date").notNull(),
    periodStart: timestamp("period_start").notNull(),
    periodEnd: timestamp("period_end").notNull(),
    gatewayInvoiceId: varchar("gateway_invoice_id", { length: 150 }),
    idempotencyKey: varchar("idempotency_key", { length: 150 }),
    metadata: jsonb("metadata").notNull(),
    paidAt: timestamp("paid_at"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingPaymentsTable = pgTable("billing_payments", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    invoiceId: uuid("invoice_id").notNull(),
    subscriptionId: uuid("subscription_id").notNull(),
    gateway: varchar("gateway", { length: 40 }).notNull(),
    gatewayPaymentId: varchar("gateway_payment_id", { length: 150 }),
    status: varchar("status", { length: 40 }).notNull(),
    amount: numeric("amount").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    failureReason: text("failure_reason"),
    idempotencyKey: varchar("idempotency_key", { length: 150 }),
    metadata: jsonb("metadata").notNull(),
    paidAt: timestamp("paid_at"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingPaymentRetriesTable = pgTable("billing_payment_retries", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    paymentId: uuid("payment_id").notNull(),
    invoiceId: uuid("invoice_id").notNull(),
    subscriptionId: uuid("subscription_id").notNull(),
    attemptNumber: integer("attempt_number").notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    scheduledAt: timestamp("scheduled_at").notNull(),
    processedAt: timestamp("processed_at"),
    failureReason: text("failure_reason"),
    createdAt: timestamp("created_at").notNull(),
});
export const billingSubscriptionChangesTable = pgTable("billing_subscription_changes", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    subscriptionId: uuid("subscription_id").notNull(),
    fromPlanId: uuid("from_plan_id"),
    toPlanId: uuid("to_plan_id").notNull(),
    changeType: varchar("change_type", { length: 40 }).notNull(),
    policy: varchar("policy", { length: 40 }).notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    effectiveAt: timestamp("effective_at").notNull(),
    remainingCreditAmount: numeric("remaining_credit_amount").notNull(),
    proratedChargeAmount: numeric("prorated_charge_amount").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    metadata: jsonb("metadata").notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingSubscriptionEventsTable = pgTable("billing_subscription_events", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    subscriptionId: uuid("subscription_id"),
    eventName: varchar("event_name", { length: 120 }).notNull(),
    entityType: varchar("entity_type", { length: 80 }).notNull(),
    entityId: varchar("entity_id", { length: 150 }).notNull(),
    payload: jsonb("payload").notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
});
export const billingCreditsTable = pgTable("billing_credits", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    invoiceId: uuid("invoice_id"),
    status: varchar("status", { length: 40 }).notNull(),
    amount: numeric("amount").notNull(),
    remainingAmount: numeric("remaining_amount").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    reason: text("reason").notNull(),
    expiresAt: timestamp("expires_at").notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingRefundsTable = pgTable("billing_refunds", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    paymentId: uuid("payment_id").notNull(),
    invoiceId: uuid("invoice_id").notNull(),
    amount: numeric("amount").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    reason: text("reason").notNull(),
    gatewayRefundId: varchar("gateway_refund_id", { length: 150 }),
    metadata: jsonb("metadata").notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const billingUsageTrackingTable = pgTable("billing_usage_tracking", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    subscriptionId: uuid("subscription_id").notNull(),
    metricName: varchar("metric_name", { length: 100 }).notNull(),
    metricValue: numeric("metric_value").notNull(),
    periodStart: timestamp("period_start").notNull(),
    periodEnd: timestamp("period_end").notNull(),
    metadata: jsonb("metadata").notNull(),
    recordedAt: timestamp("recorded_at").notNull(),
});
export const billingIdempotencyKeysTable = pgTable("billing_idempotency_keys", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    idempotencyKey: varchar("idempotency_key", { length: 150 }).notNull(),
    requestHash: varchar("request_hash", { length: 128 }).notNull(),
    responseSnapshot: jsonb("response_snapshot"),
    expiresAt: timestamp("expires_at").notNull(),
    createdAt: timestamp("created_at").notNull(),
});
